    ...leadData,
    lead_score: qualification.lead_score,
    intent: qualification.intent,
    urgency: qualification.urgency,
    buyer_type: qualification.buyer_type,
    reasoning: qualification.reasoning,
    close_probability: qualification.close_probability,
    status: status,
    booking_status: 'pending',
    is_hot_lead: qualification.lead_score >= 8
  }
}];

// Extract stored lead and check if hot
const leadData = $('Parse Qualification').first().json;
const storedLead = $input.first().json;

// Supabase returns an array
const lead = Array.isArray(storedLead) ? storedLead[0] : storedLead;

return [{
  json: {
    ...leadData,
    lead_id: lead.id,
