const leadData = $('Prepare Routing').first().json;
const briefResponse = $input.first().json;

let brief = {
  summary: 'Hot lead requiring immediate attention.',
  buyer_intent: 'Strong purchase intent detected.',
  objections: 'Price, timeline, property availability',
  suggested_questions: 'What is your ideal move-in date? | Have you been pre-approved for financing? | What are your must-have features?'
};

try {
  const content = briefResponse.choices[0].message.content;
  brief = JSON.parse(content);
} catch (e) {
  console.log('Failed to parse brief:', e.message);
}

const sanitize = (str) => (str || '').replace(/\n/g, ' | ').replace(/\r/g, '').replace(/"/g, "'");

return [{
  json: {
    ...leadData,
    brief_summary: sanitize(brief.summary),
    brief_buyer_intent: sanitize(brief.buyer_intent),
    brief_objections: sanitize(brief.objections),
    brief_suggested_questions: sanitize(brief.suggested_questions)
  }
}];

