// Categorize leads by age for 3-day and 7-day follow-up cadence
const leads = $input.all();
const now = new Date();

const reminder1 = []; // ~day 3 (72h old, never contacted)
const reminder2 = []; // ~day 7 (168h old, >=72h since last contact)
const cold = [];      // day 8+ (192h+ old, no booking)

for (const item of leads) {
  const lead = Array.isArray(item.json) ? item.json : [item.json];

  for (const l of lead) {
    if (!l.id) continue;

    const createdAt = new Date(l.created_at);
    const hoursOld = (now - createdAt) / (1000 * 60 * 60);

    const lastContacted = l.last_contacted ? new Date(l.last_contacted) : createdAt;
    const hoursSinceContact = (now - lastContacted) / (1000 * 60 * 60);

    if (hoursOld >= 192) {
      cold.push(l);
    } else if (hoursOld >= 168 && hoursSinceContact >= 72) {
      reminder2.push(l);
    } else if (hoursOld >= 72 && hoursSinceContact >= 72) {
      reminder1.push(l);
    }
  }
}

return [
  ...reminder1.map(l => ({ json: { ...l, reminder_number: 1 } })),
  ...reminder2.map(l => ({ json: { ...l, reminder_number: 2 } })),
  ...cold.map(l => ({ json: { ...l, reminder_number: 3, mark_cold: true } }))
];

